                           false);
     SimpleInstallFunction(isolate_, proto, "reduceRight",
                           Builtins::kArrayReduceRight, 1, false);
+    SimpleInstallFunction(isolate_, proto, "replaceIf",
+                          Builtins::kArrayReplaceIf, 3, false);
   }

