function hex64FromDouble(d) {
  const buf = new ArrayBuffer(8);
  const f64 = new Float64Array(buf);
  const u32 = new Uint32Array(buf);
  f64[0] = d;
  const lo = u32[0].toString(16).padStart(8, '0');
  const hi = u32[1].toString(16).padStart(8, '0');
  return '0x' + hi + lo;
}

function fmt(v) {
  if (typeof v === 'number') return `${v} / ${hex64FromDouble(v)}`;
  if (typeof v === 'undefined') return 'undefined';
  if (typeof v === 'object') return '[object ' + (v && v.constructor ? v.constructor.name : 'null') + ']';
  return String(v);
}

function readNeg(arr, idx) {
  let got;
  let ok = arr.replaceIf(idx, (x) => { got = x; return false; }, 13.37);
  return {ok, got};
}

function writeNeg(arr, idx, repl) {
  let ok = arr.replaceIf(idx, (x) => true, repl);
  return ok;
}

function dumpReads(name, arr, minIdx, maxIdx) {
  print('=== ' + name + ' length=' + arr.length + ' ===');
  for (let i = minIdx; i <= maxIdx; i++) {
    const {ok, got} = readNeg(arr, i);
    print(`${i}: ok=${ok} got=${fmt(got)}`);
  }
}

let doubles = [1.1, 2.2, 3.3, 4.4];
let objs = [{a:1}, {b:2}, {c:3}, {d:4}];
let smi = [1,2,3,4];
let mixed = [1.1, 2.2, 3.3, 4.4];
mixed[0] = {z: 9};

dumpReads('packed doubles', doubles, -12, -1);
